import { enforceTradeSafety } from '@aegis/safety';
export function calculateRisk(input) { const stopLoss = input.stopLoss ?? null; const takeProfit = input.takeProfit ?? null; const riskPerUnit = stopLoss ? Math.abs(input.entry - stopLoss) : 0; const rewardPerUnit = takeProfit ? Math.abs(takeProfit - input.entry) : 0; const rr = riskPerUnit && rewardPerUnit ? rewardPerUnit / riskPerUnit : null; const safety = enforceTradeSafety({ decision: input.decision, stopLoss, riskReward: rr }); return { entry: input.entry, stopLoss, takeProfit, riskReward: rr, maxRiskPerTrade: input.accountEquity * input.riskPct, positionSize: riskPerUnit ? (input.accountEquity * input.riskPct) / riskPerUnit : 0, decision: safety.decision }; }
